import{_ as t,o,c as r,a5 as a}from"./chunks/framework.CaodWED9.js";const u=JSON.parse('{"title":"Security operator","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/security-operator.md","filePath":"reference/components/security-operator.md"}'),i={name:"reference/components/security-operator.md"};function d(n,e,s,c,l,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="security-operator" tabindex="-1">Security operator <a class="header-anchor" href="#security-operator" aria-label="Permalink to &quot;Security operator&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The <strong>Security Operator</strong> automates security configuration across your platform mesh environment. It watches for new workspaces and automatically sets up everything needed to manage access control in Platform Mesh: creating authorization stores in <a href="https://openfga.dev/" target="_blank" rel="noreferrer"><strong>OpenFGA</strong></a>, provisioning realms and clients in <a href="https://www.keycloak.org/" target="_blank" rel="noreferrer"><strong>Keycloak</strong></a>, and keeping authorization models in sync as your APIs evolve.</p><p>Instead of manually configuring authentication and authorization for each new workspace, the Security Operator handles it all for you — ensuring consistent security posture across all organizations within your Platform Mesh deployment.</p><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>The Security Operator automates security configuration across Platform Mesh:</p><p><strong>Workspace Initialization</strong> — Security Operator initializes workspaces of <code>org</code> and <code>account</code> type. For an <code>org</code> workspace operator creates <code>Store</code> resource with authorization model and tuples, <code>IdentityProviderConfiguration</code> resource that provisions Keycloak realm and OIDC clients, and <code>WorkspaceAuthenticationConfiguration</code> resource linking realms to KCP workspaces. For an <code>account</code> type workspace operator creates tuples with account creator information.</p><p><strong>OpenFGA and Keycloak Management</strong> — Maintains authorization stores (one per organization) with fine-grained access control, writes authorization tuples mapping users to roles and resources, provisions isolated Keycloak realms with OIDC clients, and dynamically extends authorization models when APIs are bound.</p><p><strong>API Export Binding Control</strong> — Enforces deny-by-default binding policy through <code>ApiExportPolicy</code> resources, writes authorization tuples to OpenFGA enabling permitted workspaces to create <code>ApiBinding</code> resources, and automatically creates <code>AuthorizationModel</code> resources in provider workspaces to extend consumer authorization models.</p><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/security-operator" target="_blank" rel="noreferrer">platform-mesh/security-operator</a></li></ul><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>The Security Operator manages several custom resources that work together to provide comprehensive security automation.</p><h3 id="store" tabindex="-1">Store <a class="header-anchor" href="#store" aria-label="Permalink to &quot;Store&quot;">​</a></h3><p>The <code>Store</code> resource represents an <strong>OpenFGA</strong> authorization store within the Platform Mesh. Each organization gets its own <code>Store</code>, which serves as the foundation for all authorization decisions within that organization&#39;s workspaces.</p><p>The <code>Store</code> resource bridges Kubernetes and OpenFGA by:</p><ul><li>Maintaining the <strong>core authorization model</strong> that defines permission relationships</li><li>Managing <strong>tuples</strong> that map users to roles and resources</li><li>Automatically extending the authorization model when new APIs are bound</li></ul><p><code>Store</code> resources are created during workspace initialization when a new organization is provisioned or during the Platform Mesh installation phase. The Store controller watches these resources and creates corresponding stores in the OpenFGA service, then keeps the authorization model and tuples synchronized.</p><h3 id="authorizationmodel" tabindex="-1">AuthorizationModel <a class="header-anchor" href="#authorizationmodel" aria-label="Permalink to &quot;AuthorizationModel&quot;">​</a></h3><p>An <code>AuthorizationModel</code> defines the permission schema for a specific API within an OpenFGA store. While the core authorization model (bundled in each <code>Store</code>) covers Platform Mesh&#39;s built-in resources, <code>AuthorizationModel</code> resources <strong>extend</strong> this base to include provider APIs.</p><p>When somebody creates an <code>ApiBinding</code> to consume a provider&#39;s API, the Security Operator automatically:</p><ol><li>Creates an <code>AuthorizationModel</code> resource in the <strong>provider&#39;s workspace</strong></li><li>Updates the consumer organization&#39;s <code>Store</code> with the extended authorization model</li><li>Enables fine-grained access control for the newly bound API&#39;s resources</li></ol><p>This dynamic model extension means providers don&#39;t need to manually configure authorization for each consumer — the Security Operator handles it automatically as APIs are bound and unbound.</p><h3 id="identityproviderconfiguration-idp" tabindex="-1">IdentityProviderConfiguration (IDP) <a class="header-anchor" href="#identityproviderconfiguration-idp" aria-label="Permalink to &quot;IdentityProviderConfiguration (IDP)&quot;">​</a></h3><p>The <code>IdentityProviderConfiguration</code> resource configures <strong>Keycloak</strong> as the identity provider for a workspace. Each organization gets its own <strong>Keycloak realm</strong>, isolated from other organizations, with <strong>OIDC clients</strong> pre-configured for common authentication flows.</p><p>An <code>IdentityProviderConfiguration</code> resource is created during workspace initialization when a new organization is created and defines:</p><ul><li>The Keycloak realm name</li><li>OIDC clients for web applications and CLI tools</li><li>Redirect URLs for each client</li><li>Token lifespan and authentication policies</li></ul><p>The IDP controller provisions these resources in Keycloak and stores client credentials in Kubernetes <strong>secrets</strong>, making them available to applications that need to authenticate users within the workspace.</p><p><strong>Client Types:</strong></p><table tabindex="0"><thead><tr><th>Client</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td>Workspace client</td><td><strong>Confidential</strong></td><td>Web applications and services that can securely store secrets</td></tr><tr><td><code>kubectl</code> client</td><td><strong>Public</strong></td><td>CLI authentication via OIDC device flow or local callback server</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The <code>kubectl</code> client is automatically configured with localhost redirect URLs to support <code>kubectl oidc-login</code> and similar CLI authentication plugins.</p></div><h3 id="invite" tabindex="-1">Invite <a class="header-anchor" href="#invite" aria-label="Permalink to &quot;Invite&quot;">​</a></h3><p>The <code>Invite</code> resource provides a declarative way to invite users into an organization via email. Rather than manually managing user accounts in Keycloak, administrators can create <code>Invite</code> resources that trigger automated invitation workflows.</p><p>When an <code>Invite</code> is created, the Security Operator:</p><ul><li>Sends an email invitation to the specified address</li><li>Provisions a pending user account in the workspace&#39;s Keycloak realm</li><li>Grants appropriate permissions once the user accepts the invitation</li></ul><p>This enables <strong>self-service user onboarding</strong> while maintaining security boundaries between organizations.</p><h3 id="apiexportpolicy" tabindex="-1">ApiExportPolicy <a class="header-anchor" href="#apiexportpolicy" aria-label="Permalink to &quot;ApiExportPolicy&quot;">​</a></h3><p>By default, all API binding in the Platform Mesh is <strong>denied</strong> — workspaces cannot bind to a provider&#39;s <code>APIExport</code> without explicit permission. The <code>ApiExportPolicy</code> resource grants these binding permissions at scale using <strong>workspace path expressions</strong>.</p><p>An <code>ApiExportPolicy</code> consists of two parts:</p><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th></tr></thead><tbody><tr><td><code>apiExportRef</code></td><td>Identifies the <code>APIExport</code> to grant access to (name and cluster path)</td></tr><tr><td><code>allowPathExpressions</code></td><td>List of workspace path patterns that should receive bind permissions</td></tr></tbody></table><p><strong>Path Expression Syntax:</strong></p><ul><li><code>:root:orgs:example</code> — Grants permission to exactly this workspace</li><li><code>:root:orgs:example:*</code> — Grants permission to this workspace <strong>and all descendants</strong></li></ul><p><code>ApiExportPolicy</code> resources are typically created by Platform Mesh administrators when publishing APIs for broader consumption. The Security Operator watches these policies and writes the corresponding authorization tuples to OpenFGA, enabling the permitted workspaces to create <code>ApiBinding</code> resources.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="openfga-settings" tabindex="-1">OpenFGA Settings <a class="header-anchor" href="#openfga-settings" aria-label="Permalink to &quot;OpenFGA Settings&quot;">​</a></h3><p>Configure how the Security Operator connects to and manages OpenFGA stores. The <code>--fga-target</code> must point to your OpenFGA instance, while the other flags control the authorization model structure and caching behavior.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--fga-target</code></td><td>—</td><td>OpenFGA API target address</td></tr><tr><td><code>--fga-store-id-cache-ttl</code></td><td><code>24h</code></td><td>TTL for the OpenFGA store ID cache</td></tr><tr><td><code>--fga-object-type</code></td><td><code>core_platform-mesh_io_account</code></td><td>OpenFGA object type for account tuples</td></tr><tr><td><code>--fga-parent-relation</code></td><td><code>parent</code></td><td>OpenFGA parent relation name</td></tr><tr><td><code>--fga-creator-relation</code></td><td><code>owner</code></td><td>OpenFGA creator relation name</td></tr><tr><td><code>--core-module-path</code></td><td>—</td><td>Path to the core module FGA model file</td></tr><tr><td><code>--migrate-authorization-models</code></td><td><code>false</code></td><td>Enable one-time authorization model migration</td></tr><tr><td><code>--allow-member-tuples-enabled</code></td><td><code>false</code></td><td>Enable allow-member tuples management</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use <code>--migrate-authorization-models=true</code> only during initial setup or major version upgrades. This flag performs a one-time migration and should not be left enabled in production.</p></div><h3 id="keycloak-identity-provider-settings" tabindex="-1">Keycloak &amp; Identity Provider Settings <a class="header-anchor" href="#keycloak-identity-provider-settings" aria-label="Permalink to &quot;Keycloak &amp; Identity Provider Settings&quot;">​</a></h3><p>Configure Keycloak connection and identity provider behavior. The base URL and client credentials are required for operator authentication, while SMTP settings enable email-based user invitations.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--keycloak-base-url</code></td><td>—</td><td>Keycloak base URL</td></tr><tr><td><code>--keycloak-client-id</code></td><td><code>security-operator</code></td><td>Keycloak client ID for operator authentication</td></tr><tr><td><code>--idp-realm-deny-list</code></td><td>—</td><td>Comma-separated list of Keycloak realms to ignore</td></tr><tr><td><code>--idp-access-token-lifespan</code></td><td><code>28800</code></td><td>Keycloak access token lifespan in seconds (8 hours)</td></tr><tr><td><code>--idp-registration-allowed</code></td><td><code>false</code></td><td>Enable Keycloak self-registration</td></tr><tr><td><code>--idp-additional-redirect-urls</code></td><td>—</td><td>Additional redirect URLs for Keycloak clients</td></tr><tr><td><code>--idp-kubectl-client-redirect-urls</code></td><td><code>http://localhost:8000</code>, <code>http://localhost:18000</code></td><td>Redirect URLs for kubectl Keycloak client</td></tr><tr><td><code>--set-default-password</code></td><td><code>false</code></td><td>Enable setting default password for IDP users</td></tr><tr><td><code>--http-client-timeout-seconds</code></td><td><code>30</code></td><td>HTTP client timeout in seconds</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The Keycloak client secret is read from the <code>KEYCLOAK_CLIENT_SECRET</code> environment variable.</p></div><h4 id="smtp-configuration" tabindex="-1">SMTP Configuration <a class="header-anchor" href="#smtp-configuration" aria-label="Permalink to &quot;SMTP Configuration&quot;">​</a></h4><p>Configure email delivery for user invitations and notifications. All SMTP settings are optional — if not configured, email-based features will be disabled.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--idp-smtp-server</code></td><td>—</td><td>Keycloak SMTP server host</td></tr><tr><td><code>--idp-smtp-port</code></td><td><code>0</code></td><td>Keycloak SMTP server port</td></tr><tr><td><code>--idp-from-address</code></td><td>—</td><td>SMTP from address for Keycloak emails</td></tr><tr><td><code>--idp-smtp-user</code></td><td>—</td><td>SMTP username</td></tr><tr><td><code>--idp-smtp-password</code></td><td>—</td><td>SMTP password</td></tr><tr><td><code>--idp-smtp-ssl</code></td><td><code>false</code></td><td>Enable SMTP SSL</td></tr><tr><td><code>--idp-smtp-starttls</code></td><td><code>false</code></td><td>Enable SMTP STARTTLS</td></tr></tbody></table><h3 id="kcp-integration" tabindex="-1">KCP Integration <a class="header-anchor" href="#kcp-integration" aria-label="Permalink to &quot;KCP Integration&quot;">​</a></h3><p>Configure how the Security Operator connects to KCP workspaces and discovers API exports. These settings control the operator&#39;s view of the workspace hierarchy and API surface.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--kcp-kubeconfig</code></td><td><code>/api-kubeconfig/kubeconfig</code></td><td>Path to KCP kubeconfig</td></tr><tr><td><code>--api-export-endpoint-slice-name</code></td><td><code>core.platform-mesh.io</code></td><td>Core APIExportEndpointSlice name</td></tr><tr><td><code>--system-api-export-endpoint-slice-name</code></td><td><code>system.platform-mesh.io</code></td><td>System APIExportEndpointSlice name</td></tr><tr><td><code>--workspace-path</code></td><td><code>root</code></td><td>indicates in which workspace workspace type lives. It&#39;s used by Initializer and Terminator for providers setup</td></tr><tr><td><code>--workspace-type-name</code></td><td><code>security</code></td><td>Workspace type name</td></tr></tbody></table><h3 id="workspace-authentication-settings" tabindex="-1">Workspace &amp; Authentication Settings <a class="header-anchor" href="#workspace-authentication-settings" aria-label="Permalink to &quot;Workspace &amp; Authentication Settings&quot;">​</a></h3><p>Configure workspace initialization behavior and JWT token validation. The base domain is used to construct issuer URLs, while claim names determine how user identity is extracted from tokens.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--base-domain</code></td><td><code>portal.dev.local:8443</code></td><td>Base domain for constructing issuer URLs</td></tr><tr><td><code>--group-claim</code></td><td><code>groups</code></td><td>ID token group claim name</td></tr><tr><td><code>--user-claim</code></td><td><code>email</code></td><td>ID token user claim name</td></tr><tr><td><code>--additional-audiences</code></td><td>—</td><td>Additional audiences to trust in workspace JWT authentication</td></tr><tr><td><code>--domain-ca-lookup</code></td><td><code>false</code></td><td>Enable lookup of domain CA from Kubernetes secret</td></tr><tr><td><code>--development-allow-unverified-emails</code></td><td><code>false</code></td><td>Allow unverified emails in development mode</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Only enable <code>--development-allow-unverified-emails</code> in non-production environments. This flag bypasses email verification and should never be used in production.</p></div><h3 id="initializers" tabindex="-1">Initializers <a class="header-anchor" href="#initializers" aria-label="Permalink to &quot;Initializers&quot;">​</a></h3><p>Control which initialization components are active. Disabling an initializer prevents the Security Operator from automatically creating resources of that type during workspace provisioning.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--initializer-workspace-enabled</code></td><td><code>true</code></td><td>Enable workspace initialization</td></tr><tr><td><code>--initializer-idp-enabled</code></td><td><code>true</code></td><td>Enable IDP initialization</td></tr><tr><td><code>--initializer-invite-enabled</code></td><td><code>true</code></td><td>Enable invite initialization</td></tr><tr><td><code>--initializer-workspace-auth-enabled</code></td><td><code>true</code></td><td>Enable workspace auth initialization</td></tr></tbody></table><h3 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h3><p>Configure the validating webhook server for CRD validation. Webhooks are disabled by default — enable them to add admission control for Security Operator resources.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--webhooks-enabled</code></td><td><code>false</code></td><td>Enable validating webhooks</td></tr><tr><td><code>--webhooks-port</code></td><td><code>9443</code></td><td>Webhook server port</td></tr><tr><td><code>--webhooks-cert-dir</code></td><td><code>/tmp/k8s-webhook-server/serving-certs</code></td><td>Webhook certificate directory</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Refer to the <a href="https://github.com/platform-mesh/security-operator" target="_blank" rel="noreferrer">component repository</a> for the full configuration reference and environment variable options.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-127/concepts/identity-and-authorization.html">Identity and authorization</a></li><li><a href="./openfga.html">OpenFGA</a></li><li><a href="./rebac-authz-webhook.html">rebac-authz-webhook</a></li></ul><h2 id="architecture-decision-records" tabindex="-1">Architecture Decision Records <a class="header-anchor" href="#architecture-decision-records" aria-label="Permalink to &quot;Architecture Decision Records&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/architecture/blob/main/adr/002-apiexport-binding-access-control.md" target="_blank" rel="noreferrer">ADR-002: APIExport Binding Access Control</a></li></ul>',73)])])}const m=t(i,[["render",d]]);export{u as __pageData,m as default};
